    private async Task LoadMotors()
    {
        await Task.Delay(500);

        MotorList = filteredMotorList = await MotorPolicyService.GetIssueMotor();

        StateHasChanged();
    }

    private void OnMotorSearchTextChanged(ChangeEventArgs changeEventArgs, string columnTitle)
    {
        string searchText = changeEventArgs.Value.ToString();
        IsGridViewFiltered = true;

        switch (columnTitle)
        {
            case "CoverNoteNo":
                filteredMotorList = MotorList.Where(motor => motor.CoverNoteNo.ToString().Contains(searchText)).ToList();
                break;
            case "QuotationNo":
                filteredMotorList = MotorList.Where(motor => motor.QuotationNo.ToString().Contains(searchText)).ToList();
                break;
            case "JPJStatus":
                filteredMotorList = MotorList.Where(motor => motor.JPJStatus.ToString().Contains(searchText)).ToList();
                break;
            case "AgentCode":
                filteredMotorList = MotorList.Where(motor => motor.AgentCode.ToString().Contains(searchText)).ToList();
                break;
            case "IssueDate":
                filteredMotorList = MotorList.Where(motor => motor.IssueDate.ToString().Contains(searchText)).ToList();
                break;
            default:
                Console.WriteLine("Default case");
                break;
        }
    }

    private async Task update()
    {
        if (covernote == null)
        {
            ToastService.ShowWarning("Please enter Cover Note No.");
        }
        else if (covernote == "")
        {
            IsGridViewFiltered = true;
            AllMtrList = filteredAllMtrList = await MotorPolicyService.SearchMotor(covernote.Replace(" ", ""));
            StateHasChanged();

            ToastService.ShowWarning("Please enter Cover Note No.");
        }
        else
        {
            string[] result = covernote.Replace(" ", "").Split(new string[] { "," }, StringSplitOptions.RemoveEmptyEntries);

            foreach (string strCN in result)
            {
                i = i + 1;

                AllMtrList = filteredAllMtrList = await MotorPolicyService.GetPendMotor(strCN);

                if (AllMtrList == null || AllMtrList.Count == 0)
                {
                    Err = true;

                    if (i == 1)
                    {
                        ErrCN = strCN;
                    }
                    else
                    {
                        ErrCN = ErrCN + "," + strCN;
                    }
                }
            }

            if (i == 1)
            {
                ErrCN = ErrCN + " is";
            }
            else
            {
                ErrCN = ErrCN + " are";
            }

            i = 0;

            if (Err == true)
            {
                IsGridViewFiltered = true;
                AllMtrList = filteredAllMtrList = await MotorPolicyService.SearchMotor(covernote.Replace(" ", ""));
                StateHasChanged();

                ToastService.ShowError(ErrCN + " not under Policy Issued/ pending JPJ");
            }
            else
            {
                MotorPolicyService.UpdStatus(covernote.Replace(" ", ""));
                IsGridViewFiltered = true;
                AllMtrList = filteredAllMtrList = await MotorPolicyService.SearchMotor(covernote.Replace(" ", ""));
                MotorList = filteredMotorList = await MotorPolicyService.GetIssueMotor();
                StateHasChanged();
            }
        }
    }

    private async Task search()
    {
        if (covernote == "" || covernote == null)
        {
            ToastService.ShowWarning("Please enter Cover Note No.");
        }
        else
        {
            IsGridViewFiltered = true;
            AllMtrList = filteredAllMtrList = await MotorPolicyService.SearchMotor(covernote.Replace(" ", ""));
            StateHasChanged();
        }
    }

    private async Task export()
    {
        if (covernote == "" || covernote == null)
        {
            ToastService.ShowWarning("Please enter Cover Note No.");
        }
        else
        {
            AddClass = true;

            MotorPolicyService.ExportTo(covernote.Replace(" ", ""));

            await addZipEntry(path);

            AddClass = false;

            ToastService.ShowSuccess("Generate files Completed.");
        }
    }

    private async Task addZipEntry(string PathStr)
    {
        DirectoryInfo di = new DirectoryInfo(PathStr);

        foreach (DirectoryInfo item in di.GetDirectories())
        {
            await addZipEntry(item.FullName);
        }

        using (MemoryStream ms = new MemoryStream())
        {
            using (ZipOutputStream zipSream = new ZipOutputStream(ms))
            {
                foreach (FileInfo item in di.GetFiles())
                {
                    FileStream fs = File.OpenRead(item.FullName);
                    byte[] buffer = new byte[fs.Length];
                    fs.Read(buffer, 0, buffer.Length);
                    string strEntryName = item.FullName;
                    ZipEntry entry = new ZipEntry(strEntryName);
                    zipSream.PutNextEntry(entry);
                    zipSream.Write(buffer, 0, buffer.Length);
                    fs.Close();
                }
            }

            await FileSaver.SaveAsBase64("Renewal_CN.zip", Convert.ToBase64String(ms.ToArray()), "application/zip");
        }
    }

